    /**
     * Sent At
     */
    sent_at?: string | null;
    /**
     * Recipient Count
     */
    recipient_count?: number;
    /**
     * Scheduled At
     *
     * Absolute time to send a scheduled announcement (mutually exclusive with relative scheduling).
     */
